const items = $input.all();
const emails = items.map(i => i.json);
const unread = emails.length;
const meetings = emails.filter(e => e.subject?.match(/meeting|call|invite|zoom|teams/i)).slice(0, 8).map(e => ({ subject: e.subject, from: e.from?.emailAddress?.name || e.from?.emailAddress?.address || '' }));
const people = emails.filter(e => e.from?.emailAddress?.address?.endsWith('@adobe.com')).slice(0, 8).map(e => ({ subject: e.subject, from: e.from?.emailAddress?.name || '' }));
const flagged = emails.filter(e => e.flag?.flagStatus === 'flagged').map(e => ({ subject: e.subject, from: e.from?.emailAddress?.name || '' }));
return [{ json: { unreadCount: unread, meetings, people, flagged } }];

const events = $input.all().map(i => i.json);
const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const today = new Date().toDateString();
const mapped = events.map(ev => {
  const start = new Date(ev.start?.dateTime || ev.start?.date);
  const isToday = start.toDateString() === today;
  const h = start.getHours() % 12 || 12;
  const m = String(start.getMinutes()).padStart(2, '0');
  const ampm = start.getHours() >= 12 ? 'PM' : 'AM';
  return {
    day: `${days[start.getDay()]} ${start.toLocaleDateString('en-US',{month:'short',day:'numeric'})}`,
    time: ev.isAllDay ? 'All day' : `${h}:${m} ${ampm}`,
    title: ev.subject || ev.summary,
    organizer: ev.organizer?.emailAddress?.name || '',
    isToday,
    tag: ev.subject?.match(/soccer|BTB|raiders/i) ? 'Soccer' : ev.subject?.match(/football|CDMFA/i) ? 'Football' : ev.subject?.match(/demo/i) ? 'Demo' : ev.subject?.match(/1:1/i) ? '1:1' : null,
    tagColor: ev.subject?.match(/soccer|BTB|raiders/i) ? 'blue' : ev.subject?.match(/football/i) ? 'orange' : ev.subject?.match(/demo/i) ? 'orange' : 'blue'
  };
});
const weekLabel = `Week of ${new Date().toLocaleDateString('en-US',{month:'short',day:'numeric'})} – ${new Date(Date.now()+6*864e5).toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})}`;
return [{ json: { weekLabel, events: mapped } }];

const items = $input.all();
const tagMap = { soccer: ['soccer','btb','raiders','forza','juventus'], football: ['football','cdmfa','effa'], kyra: ['kyra'], jayleen: ['jayleen'], family: ['family'] };
const filtered = items.map(i => {
  const from = i.json.payload?.headers?.find(h => h.name === 'From')?.value || '';
  const subject = i.json.payload?.headers?.find(h => h.name === 'Subject')?.value || '';
  let tag = 'Family'; let tagColor = 'purple';
  const sl = subject.toLowerCase();
  if (sl.match(/soccer|btb|raiders/)) { tag = 'Soccer'; tagColor = 'blue'; }
  else if (sl.match(/football|cdmfa/)) { tag = 'Football'; tagColor = 'orange'; }
  else if (sl.match(/kyra/)) { tag = 'Kyra'; tagColor = 'purple'; }
  return { from: from.split('<')[0].trim(), subject, tag, tagColor };
}).slice(0, 10);
return [{ json: { unreadCount: items.length, filtered } }];

const events = $input.all().map(i => i.json);
const days = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
const today = new Date().toDateString();
const mapped = events.map(ev => {
  const start = new Date(ev.start?.dateTime || ev.start?.date);
  const isToday = start.toDateString() === today;
  const h = start.getHours() % 12 || 12;
  const m = String(start.getMinutes()).padStart(2, '0');
  const ampm = start.getHours() >= 12 ? 'PM' : 'AM';
  return {
    day: `${days[start.getDay()]} ${start.toLocaleDateString('en-US',{month:'short',day:'numeric'})}`,
    time: !ev.start?.dateTime ? 'All day' : `${h}:${m} ${ampm}`,
    title: ev.summary,
    location: ev.location || '',
    organizer: ev.organizer?.displayName || '',
    isToday,
    isPersonal: true,
    tag: ev.summary?.match(/soccer|BTB|raiders/i) ? 'Soccer' : ev.summary?.match(/football|CDMFA/i) ? 'Football' : ev.summary?.match(/theo|jayleen|kyra/i) ? 'Family' : 'Personal',
    tagColor: ev.summary?.match(/soccer/i) ? 'blue' : ev.summary?.match(/football/i) ? 'orange' : ev.summary?.match(/theo|jayleen|kyra/i) ? 'purple' : 'gray'
  };
});
const weekLabel = `Week of ${new Date().toLocaleDateString('en-US',{month:'short',day:'numeric'})} – ${new Date(Date.now()+6*864e5).toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})}`;
return [{ json: { weekLabel, events: mapped } }];

const items = $input.all();
const tagMap = { Partnership: /partner|collab|introduction|i reach out/i, Event: /rate card|booth|festival|event/i, Analytics: /recap|report|analytics/i, Banking: /bank|statement/i, Business: /business|product|profile/i };
const filtered = items.filter(i => !i.json.subject?.match(/uline|DHL routine|catalog/i)).map(i => {
  const from = (i.json.from || '').split('<')[0].trim();
  const subject = i.json.subject || '';
  let tag = 'Business'; let tagColor = 'blue';
  for (const [t, re] of Object.entries(tagMap)) { if (re.test(subject) || re.test(from)) { tag = t; tagColor = t === 'Partnership' ? 'green' : t === 'Event' ? 'amber' : t === 'Analytics' ? 'blue' : t === 'Banking' ? 'gray' : 'blue'; break; } }
  return { from, subject, tag, tagColor };
}).slice(0, 10);
return [{ json: { unreadCount: items.length, filtered } }];
